const payload = $input.first().json.body;

// Extract lead data from Meta Ads payload
const fullName = payload.full_name || payload['Full name'] || '';
const email = (payload.email || payload.Email || '').trim().toLowerCase();
const phoneNumber = payload.phone_number || payload['Phone number'] || '';
const jobTitle = payload['請問您的職位'] || '';
const restaurantName = payload['您經營的餐廳/品牌名稱'] || '';
const productInterested = payload['對oddle哪種產品感興趣'] || payload['對Oddle哪種產品感興趣'] || '';

// Extract Line ID (two possible field names)
const lineId = payload['提供您的 Line id，讓我們可以盡快與您聯繫'] || payload['提供您的_line_id，讓我們可以盡快與您聯繫'] || '';

// Parse timestamp to date format (YYYY-MM-DD)
const rawTimestamp = payload.created_time || '';
let submissionDate = '';
if (rawTimestamp) {
  const date = new Date(rawTimestamp);
  submissionDate = date.toISOString().split('T')[0];
}

// Extract domain from email for company search
function extractEmailDomain(email) {
  if (!email || !email.includes('@')) return '';
  return email.split('@')[1].toLowerCase().trim();
}

// Email domain blacklist (B2C email providers)
const emailBlacklist = [
  'gmail.com', 'yahoo.com', 'outlook.com', 'hotmail.com', 'live.com', 'msn.com',
  'icloud.com', 'me.com', 'mac.com', 'aol.com', 'protonmail.com', 'proton.me',
  'ymail.com', 'rocketmail.com', 'mail.com', 'zoho.com', 'gmx.com', 'gmx.net',
  'yahoo.com.tw', 'yahoo.com.hk', 'qq.com', '163.com', '126.com'
];

function isEmailBlacklisted(domain) {
  if (!domain) return true;
  return emailBlacklist.some(bl => domain === bl || domain.endsWith('.' + bl));
}

const emailDomain = extractEmailDomain(email);
const validEmailDomain = (!isEmailBlacklisted(emailDomain)) ? emailDomain : '';

// Determine if we should search for company
const shouldSearchCompany = validEmailDomain || restaurantName;

return [{
  json: {
    fullName,
    email,
    phoneNumber,
    jobTitle,
    restaurantName,
    productInterested,
    lineId,
    submissionDate,
    emailDomain: validEmailDomain,
    country: 'Taiwan',
    shouldSearchCompany,
    adId: payload.ad_id || '',
    adName: payload.ad_name || '',
    campaignName: payload.campaign_name || '',
    formName: payload.form_name || '',
    platform: payload.platform || ''
  }
}];

